{"Configuration":"/** @param {Context} context */
const SetValue = async (context) => {

    if (!context?.Form?.InvoicePage?.DownPaymentRequest?.Value) {
        return "";
    }

    if (context?.Form?.InvoicePage?.DPApproverPM?.Value == "Approved" &&
        context?.Form?.InvoicePage?.DPIssueDate?.Value == "") {
        return "Julie Blanco";
    }

    if (context?.Form?.InvoicePage?.DPIssueDate?.Value !== "") {
        return "N/A";
    }

    const grid = context?.Form?.InvoicePage?.DPInvoiceDetails || [];

    if (grid.length == 0) {
        return "Coordinator";
    }

    const mostRecentAction = grid[0];
    const recentApprover = mostRecentAction?.DPReviewer?.Text || "";
    const recentStatus = mostRecentAction?.DownpaymentStatus?.Text || "";
    const stayStatuses = ["Received", "In Review", "Submitted to IOUs"];

    const coordinatorLastNames = ["Cervantes", "Jancik", "Enotiades", "Chavez", "Quintanilla", "Mendez", "Avila"];
    const isCoordinator = coordinatorLastNames.some(name => recentApprover.includes(name));

    const pmLastNames = ["Accardo", "Velores", "Landeros"];
    const isPM = pmLastNames.some(name => recentApprover.includes(name));

    // Pending Corrections - always goes to contractor
    if (recentStatus == "Pending Corrections") {
        return context?.Form?.InvoicePage?.DPInstallationContractor?.Text || "Coordinator";
    }

    // Corrections Submitted - return to previous actor
    if (recentStatus == "Corrections Submitted") {
        return grid[1]?.DPReviewer?.Text || "Coordinator";
    }

    // Rejected - drop down one tier
    if (recentStatus == "Rejected") {
        if (isPM) return "Coordinator";
        if (isCoordinator) return context?.Form?.InvoicePage?.DPInstallationContractor?.Text || "Coordinator";
        return "Coordinator";
    }

    // PM routing - approved goes straight to Julie
    if (isPM) {
        if (stayStatuses.includes(recentStatus)) return recentApprover;
        if (recentStatus == "Approved") return "Julie Blanco";
    }

    // Coordinator routing - approved escalates to PM
    if (isCoordinator) {
        if (stayStatuses.includes(recentStatus)) return recentApprover;
        if (recentStatus == "Approved") return "Program Manager";
    }

    // Contractor stay status - return to last internal reviewer
    if (stayStatuses.includes(recentStatus)) {
        return grid[0]?.DPReviewer?.Text || "Coordinator";
    }

    return "Coordinator";
};","ClearValueOnTrue":false,"ClearValueOnFalse":false,"Fields":[{"ModelKey":"DPReviewer","FieldName":"DPReviewer","IsSystemModelKey":false},{"ModelKey":"Form.InvoicePage.DPInvoiceDetails","FieldName":"DPInvoiceDetails","IsSystemModelKey":false},{"ModelKey":"Form.InvoicePage.DPIssueDate","FieldName":"DPIssueDate","IsSystemModelKey":false},{"ModelKey":"Form.InvoicePage.DownPaymentRequest","FieldName":"DownPaymentRequest","IsSystemModelKey":false},{"ModelKey":"Form.InvoicePage.DPApproverPM","FieldName":"DPApproverPM","IsSystemModelKey":false},{"ModelKey":"DownpaymentStatus","FieldName":"DownpaymentStatus","IsSystemModelKey":false}]}

