   const grid = context?.Form?.InvoicePage?.EnrollmentInvoiceDetails || [];
   if (grid.length === 0) return "Pending Review";

   const recentStatus = grid[0]?.EnrollmentStatus?.Value || "";
   const recentApprover = grid[0]?.EnrollmentReviewer?.Text || "";

   // Check for rejections/corrections first
   if (recentStatus == "Rejected") return "Rejected";
   if (recentStatus == "Pending Corrections") return "Pending Corrections";
   if (recentStatus == "Corrections Submitted") return "Corrections Review";

