   if (recentApprover == "Dan Accardo" && recentStatus == "Approved") {
       return "Approved for Final Payment";
   }
   if ((recentApprover == "Chuk Mmegwa" || recentApprover == "Luis Cervantes" || recentApprover == "Harris Enotiades" || recentApprover == "Jeremiah Jancik" ) && recentStatus == "Approved") {
       return "Pending Review by PM";
   }

   // Fallback
   return recentStatus || "Pending Review";
