{"Configuration":"/** @param {Context} context */
const SetValue = async (context) => {

    if (!context?.Form?.InvoicePage?.AssessmentInvoice?.Value) {
        return "";
    }

    if (context?.Form?.InvoicePage?.IssueDate_Assessment?.Value !== "") {
        return "N/A";
    }

    const grid = context?.Form?.InvoicePage?.AssessmentInvoiceDetailsGrid || [];

    if (grid.length == 0) {
        return "Coordinator";
    }

    const mostRecentAction = grid[0];
    const recentApprover = mostRecentAction?.Reviewer_Assessment?.Text || "";
    const recentStatus = mostRecentAction?.ReviewStatus_Assessment?.Value || "";
    const stayStatuses = ["Received", "In Review"];

    const coordinatorLastNames = ["Cervantes", "Jancik", "Enotiades", "Chavez", "Quintanilla", "Mendez", "Avila"];
    const isCoordinator = coordinatorLastNames.some(name => recentApprover.includes(name));

    const pmLastNames = ["Accardo", "Velores", "Landeros"];
    const isPM = pmLastNames.some(name => recentApprover.includes(name));

    // Pending Corrections - always goes to contractor
    if (recentStatus == "Pending Corrections") {
        return context?.Form?.InvoicePage?.AssessmentContractorName?.Text || "Coordinator";
    }

    // Corrections Submitted - walk back to find most recent non-contractor reviewer
    if (recentStatus == "Corrections Submitted") {
        for (let i = 1; i < grid.length; i++) {
            const previousReviewer = grid[i]?.Reviewer_Assessment?.Text || "";
            if (previousReviewer !== context?.Form?.InvoicePage?.AssessmentContractorName?.Text) {
                return previousReviewer;
            }
        }
        return "Coordinator";
    }

    // Rejected - drop down one tier
    if (recentStatus == "Rejected") {
        if (isPM) return "Coordinator";
        if (isCoordinator) return context?.Form?.InvoicePage?.AssessmentContractorName?.Text || "Coordinator";
        return "Coordinator";
    }

    // PM routing - approved goes to Julie
    if (isPM) {
        if (stayStatuses.includes(recentStatus)) return recentApprover;
        if (recentStatus == "Approved") return "Julie Blanco";
    }

    // Coordinator routing - approved escalates to PM
    if (isCoordinator) {
        if (stayStatuses.includes(recentStatus)) return recentApprover;
        if (recentStatus == "Approved") return "Program Manager";
    }

    // Contractor stay status - return to last internal reviewer
    if (stayStatuses.includes(recentStatus)) {
        return grid[0]?.Reviewer_Assessment?.Text || "Coordinator";
    }

    return "Coordinator";
};","ClearValueOnTrue":false,"ClearValueOnFalse":false,"Fields":[{"ModelKey":"Form.InvoicePage.AssessmentInvoice","FieldName":"AssessmentInvoice","IsSystemModelKey":false},{"ModelKey":"Form.InvoicePage.AssessmentContractorName","FieldName":"AssessmentContractorName","IsSystemModelKey":false},{"ModelKey":"Reviewer_Assessment","FieldName":"Reviewer_Assessment","IsSystemModelKey":false},{"ModelKey":"ReviewStatus_Assessment","FieldName":"ReviewStatus_Assessment","IsSystemModelKey":false},{"ModelKey":"Form.InvoicePage.IssueDate_Assessment","FieldName":"IssueDate_Assessment","IsSystemModelKey":false},{"ModelKey":"Form.InvoicePage.AssessmentInvoiceDetailsGrid","FieldName":"AssessmentInvoiceDetailsGrid","IsSystemModelKey":false}]}

