const SetValue = async (context) => {
   // Check issue date first - highest priority status
   const issueDate = context?.Form?.InvoicePage?.IssueDate_Assessment?.Value;
   if (issueDate) return "Payment Issued";

   // Check if assessment invoice exists
   if (!context?.Form?.InvoicePage?.AssessmentInvoice?.Value) {
       return "";
   }

   // Get most recent action from grid
   const grid = context?.Form?.InvoicePage?.AssessmentInvoiceDetailsGrid || [];
   if (grid.length == 0) return "Pending Review";

   const recentStatus = grid[0]?.ReviewStatus_Assessment?.Text || "";
   const recentReviewer = grid[0]?.Reviewer_Assessment?.Text || "";

   // Check for rejections/corrections first - highest priority
   if (recentStatus == "Rejected") return "Rejected";
   if (recentStatus == "Pending Corrections") return "Pending Corrections";
   if (recentStatus == "Corrections Submitted") return "Correction Review";

   // Check approval progression based on who approved
   if (recentReviewer == "Dan Accardo" && recentStatus == "Approved") {
       return "Approved for Final Payment";
   }
   if ((recentReviewer == "Chuk Mmegwa" || recentReviewer == "Luis Cervantes") && recentStatus == "Approved") {
       return "Pending PM Review";
   }

   // Return the most recent status or empty
   return recentStatus || "Pending Review";
